module top_module(
    input clk,
    input reset,
    input [31:0] in,
    output reg [31:0] out
);reg [31:0] unused_counter;

always @(posedge clk, posedge reset) begin
    if (reset) begin
        unused_counter <= 0;
        out <= 0;
    end
    else begin
        unused_counter <= unused_counter + 1;
        if (in < unused_counter) begin
            out <= 1;
        end
    end
end

endmodule
